(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[1847],{5123:(s,n,a)=>{"use strict";a.r(n),a.d(n,{data:()=>e});const e={key:"v-5438f8d7",path:"/sql/view/subquery/",title:"Subquery",lang:"en-US",frontmatter:{},excerpt:"",headers:[],filePathRelative:"sql/view/subquery/README.md",git:{updatedTime:162676698e4,contributors:[]}}},9413:(s,n,a)=>{"use strict";a.r(n),a.d(n,{default:()=>p});const e=(0,a(6252).uE)('<h1 id="subquery" tabindex="-1"><a class="header-anchor" href="#subquery" aria-hidden="true">#</a> Subquery</h1><p>โดยภายใน Subquery ก็จะมี SQL ที่เอาไว้เลือก (SELECT, FROM, WHERE) แต่ด้วยการใช้ subqueries ก็จะสามารถเลือกวิธีการ JOIN ตารางได้</p><p>In = จะเลือกข้อมูลที่มี attribute บางข้อมูลใน subqueries ที่เหมือนกันกับของ query หลัก Any = บางข้อมูลใน subqueries (แต่สามารถใส่ <code>&gt;</code> <code>&lt;</code> <code>&gt;=</code> พวกนี้ได้) All = ทุกข้อมูลใน subqueries (สามารถใส่ <code>&gt;</code> <code>&lt;</code> <code>&gt;=</code> พวกนี้ได้)</p><p>แสดงพนักงานที่ได้รับเงินเดือนตำ่สุดของแผนกต่างๆ</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> employee_id<span class="token punctuation">,</span> last_name<span class="token punctuation">,</span> job_id<span class="token punctuation">,</span> salary\n<span class="token keyword">FROM</span> employees\n<span class="token keyword">WHERE</span> salary <span class="token operator">IN</span> <span class="token punctuation">(</span>\n                  <span class="token keyword">SELECT</span> <span class="token function">MIN</span><span class="token punctuation">(</span>salary<span class="token punctuation">)</span>\n                  <span class="token keyword">FROM</span> employees\n                  <span class="token keyword">GROUP</span> <span class="token keyword">BY</span> department_id\n                <span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>แสดงข้อมูล employee ที่ได้เงินเดือนน้อยกว่าเงินเดือนพนักงานที่มีรหัสพนักงาน = ‘IT_PROG’ บางคน และไม่แสดงพนักงานที่มีรหัสงาน IT_PROG</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>    <span class="token keyword">SELECT</span> employee_id<span class="token punctuation">,</span> last_name<span class="token punctuation">,</span> job_id<span class="token punctuation">,</span> salary\n    <span class="token keyword">FROM</span> employees\n    <span class="token keyword">WHERE</span> salary <span class="token operator">&lt;</span> <span class="token keyword">ALL</span><span class="token punctuation">(</span>\n                    <span class="token keyword">SELECT</span> salary\n                    <span class="token keyword">FROM</span> employees\n                    <span class="token keyword">WHERE</span> job_id <span class="token operator">=</span> <span class="token string">&#39;IT_PROG&#39;</span><span class="token punctuation">)</span>\n    <span class="token operator">AND</span> job_id <span class="token operator">&lt;&gt;</span> <span class="token string">&#39;IT_PROG&#39;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div>',7),p={render:function(s,n){return e}}}}]);